```ts
import { Effect, Data } from "effect";

interface Profile { readonly id: string; readonly name: string }
interface Preferences { readonly theme: string }
interface Order { readonly id: string; readonly total: number }

class ProfileMissing extends Data.TaggedError("ProfileMissing")<{ readonly id: string }> {}
class PrefsUnavailable extends Data.TaggedError("PrefsUnavailable")<{ readonly id: string }> {}
class OrdersUnavailable extends Data.TaggedError("OrdersUnavailable")<{ readonly id: string }> {}

declare const fetchProfile: (id: string) => Effect.Effect<Profile, ProfileMissing>;
declare const fetchPrefs: (id: string) => Effect.Effect<Preferences, PrefsUnavailable>;
declare const fetchOrders: (id: string) => Effect.Effect<ReadonlyArray<Order>, OrdersUnavailable>;

export const enrich = (
  id: string
): Effect.Effect<[Profile, Preferences, ReadonlyArray<Order>], ProfileMissing | PrefsUnavailable | OrdersUnavailable> =>
  Effect.gen(function* () {
    return yield* Effect.all(
      [fetchProfile(id), fetchPrefs(id), fetchOrders(id)] as const,
      { concurrency: "unbounded" }
    );
  });
```

Passing a tuple to `Effect.all` preserves per-position types in the success channel; `{ concurrency: "unbounded" }` runs all three in parallel, and any branch's failure cancels the rest while merging into the union `E` channel. The `Effect.gen` wrapper makes the parallel fan-out easy to extend with post-processing steps.

```ts
import { Effect } from "effect";

interface ImageBlob { readonly bytes: Uint8Array }

declare const transform: (path: string) => Effect.Effect<ImageBlob, Error>;

const paths: ReadonlyArray<string> = ["a.png", "b.png", "c.png", "d.png"];
const jobs = paths.map(transform);

// Sequential: default `Effect.all([...])` runs one-at-a-time.
export const serial: Effect.Effect<ReadonlyArray<ImageBlob>, Error> =
  Effect.all(jobs).pipe(Effect.map((xs) => xs));

// Bounded parallel: `{ concurrency: 3 }` caps in-flight work at 3 fibres.
export const poolOf3: Effect.Effect<ReadonlyArray<ImageBlob>, Error> =
  Effect.all(jobs, { concurrency: 3 }).pipe(Effect.map((xs) => xs));
```

The default behaviour of `Effect.all` is sequential; a numeric `concurrency` option converts it into a bounded worker pool that still preserves ordering of the returned array. The trailing `.pipe(Effect.map(...))` is a no-op here — included to show where downstream transforms naturally slot in.

```ts
import { Effect, Data } from "effect";

interface User { readonly id: string }
interface Post { readonly id: string }
interface Friend { readonly id: string }

class FetchError extends Data.TaggedError("FetchError")<{ readonly what: string }> {}

declare const getUser: (id: string) => Effect.Effect<User, FetchError>;
declare const getPosts: (id: string) => Effect.Effect<ReadonlyArray<Post>, FetchError>;
declare const getFriends: (id: string) => Effect.Effect<ReadonlyArray<Friend>, FetchError>;

export const loadDashboard = (
  id: string
): Effect.Effect<[User, ReadonlyArray<Post>, ReadonlyArray<Friend>], FetchError> =>
  Effect.gen(function* () {
    const tuple = yield* Effect.all(
      [getUser(id), getPosts(id), getFriends(id)] as const,
      { concurrency: "unbounded" }
    );
    return tuple;
  });
```

`Effect.all` with a tuple literal mirrors `Promise.all`'s tuple-preserving behaviour; `{ concurrency: "unbounded" }` matches Promise.all's fully-parallel semantics while keeping the `E` channel typed as `FetchError`.

