import { Effect, Data } from "effect";

class UploadError extends Data.TaggedError("UploadError")<{ readonly path: string }> {}

declare const upload: (path: string) => Effect.Effect<string, UploadError>;

// Before: sequential — the default of Effect.all is one-at-a-time.
export const uploadAllSerial = (
  paths: ReadonlyArray<string>
): Effect.Effect<ReadonlyArray<string>, UploadError> =>
  Effect.all(paths.map(upload));

// After: up to 5 fibres in flight at a time, input order preserved.
export const uploadAll = (
  paths: ReadonlyArray<string>
): Effect.Effect<ReadonlyArray<string>, UploadError> =>
  Effect.all(paths.map(upload), { concurrency: 5 }).pipe(
    Effect.map((urls) => urls)
  );
```

`concurrency: 5` caps the worker pool; the return is still `ReadonlyArray<string>` aligned with the input order. The trailing `.pipe(Effect.map(...))` is where caller-side transforms (e.g. logging, mapping to a response) usually attach.

`Effect.all(jobs)` defaults to sequential — one at a time, in order. `{ concurrency: "unbounded" }` fans every job out at once. A numeric value like `{ concurrency: 8 }` is a bounded worker pool: at most N fibres in flight, with the remainder queued. `{ concurrency: "inherit" }` uses whatever concurrency was set by an outer `Effect.withConcurrency` scope.

```ts
import { Effect, Data } from "effect";

class HttpError extends Data.TaggedError("HttpError")<{ readonly url: string }> {}

declare const fetch: (url: string) => Effect.Effect<string, HttpError>;

const urls: ReadonlyArray<string> = ["/a", "/b", "/c", "/d"];
const jobs = urls.map(fetch);

export const serial: Effect.Effect<ReadonlyArray<string>, HttpError> = Effect.all(jobs);
export const unbounded: Effect.Effect<ReadonlyArray<string>, HttpError> = Effect.all(jobs, {
  concurrency: "unbounded",
});
export const pooled: Effect.Effect<ReadonlyArray<string>, HttpError> = Effect.all(jobs, {
  concurrency: 2,
});
export const inherited: Effect.Effect<ReadonlyArray<string>, HttpError> = Effect.all(jobs, {
  concurrency: "inherit",
});

// Same four, composed inside a generator so downstream code can add steps.
export const pooledThenLog: Effect.Effect<ReadonlyArray<string>, HttpError> =
  Effect.gen(function* () {
    const bodies = yield* pooled;
    return bodies;
  });
```

All four share the same success and error types; only the runtime scheduling changes.

```ts
import { Effect, Context, Layer, Data } from "effect";

class CacheError extends Data.TaggedError("CacheError")<{ readonly key: string }> {}

interface Cache {
  readonly warm: (k: string) => Effect.Effect<void, CacheError>;
  readonly read: (k: string) => Effect.Effect<string, CacheError>;
}
const Cache = Context.GenericTag<Cache>("app/Cache");

export const program: Effect.Effect<string, CacheError, Cache> =
  Effect.gen(function* () {
    const cache = yield* Cache;
    // Parallel warm-up.
    yield* Effect.all(
      [cache.warm("a"), cache.warm("b"), cache.warm("c")] as const,
      { concurrency: "unbounded", discard: true }
    );
    // Sequential read after the warm-up resolves.
    return yield* cache.read("a");
  });

export const CacheLive = Layer.succeed(Cache, {
  warm: () => Effect.void,
  read: () => Effect.succeed("hit"),
});
```

The parallel `Effect.all` finishes before the surrounding generator continues; the trailing `cache.read` is a plain sequential yield inside `Effect.gen`.

