import { Effect, Data } from "effect";

interface Quote { readonly venue: string; readonly bid: number; readonly ask: number }

class FeedError extends Data.TaggedError("FeedError")<{ readonly venue: string }> {}

declare const feedA: () => Effect.Effect<Quote, FeedError>;
declare const feedB: () => Effect.Effect<Quote, FeedError>;
declare const feedC: () => Effect.Effect<Quote, FeedError>;

const bestOf = (qs: ReadonlyArray<Quote>): Quote =>
  qs.reduce((acc, q) => (q.bid > acc.bid ? q : acc));

export const bestBid: Effect.Effect<Quote, FeedError> =
  Effect.gen(function* () {
    const quotes = yield* Effect.all(
      [feedA(), feedB(), feedC()] as const,
      { concurrency: "unbounded" }
    );
    return bestOf(quotes);
  });
```

Firing the three feeds in parallel minimises tail latency; the surrounding generator then reduces the typed 3-tuple into a single winning `Quote`.

```ts
import { Effect, Data } from "effect";

class JobError extends Data.TaggedError("JobError")<{ readonly id: string }> {}

declare const job: (id: string) => Effect.Effect<number, JobError>;

// Partially-applied Effect.all with fixed concurrency.
const allPar4 = Effect.allWith({ concurrency: 4 });

export const runSmall = (ids: ReadonlyArray<string>): Effect.Effect<ReadonlyArray<number>, JobError> =>
  allPar4(ids.map(job));

export const runLarge = (ids: ReadonlyArray<string>): Effect.Effect<ReadonlyArray<number>, JobError> =>
  allPar4(ids.map(job));

// Contrast: sequential default, no Effect.allWith.
export const runSerial = (ids: ReadonlyArray<string>): Effect.Effect<ReadonlyArray<number>, JobError> =>
  Effect.all(ids.map(job));

// Empty-batch sanity wrapper.
export const runOrEmpty = (ids: ReadonlyArray<string>): Effect.Effect<ReadonlyArray<number>, JobError> =>
  ids.length === 0 ? Effect.succeed([] as ReadonlyArray<number>) : runSmall(ids);
```

`Effect.allWith({...})` captures the options so both `runSmall` and `runLarge` share the same bounded-concurrency policy without restating it; `Effect.succeed([])` short-circuits the empty-list case before touching the pool.

```ts
import { Effect, Data } from "effect";

interface DashStatus { readonly auth: "ok"; readonly billing: "ok"; readonly search: "ok" }

class AuthDown extends Data.TaggedError("AuthDown")<{}> {}
class BillingDown extends Data.TaggedError("BillingDown")<{}> {}
class SearchDown extends Data.TaggedError("SearchDown")<{}> {}
class ServiceDown extends Data.TaggedError("ServiceDown")<{ readonly which: string }> {}

declare const pingAuth: () => Effect.Effect<void, AuthDown>;
declare const pingBilling: () => Effect.Effect<void, BillingDown>;
declare const pingSearch: () => Effect.Effect<void, SearchDown>;

export const health: Effect.Effect<DashStatus, ServiceDown> =
  Effect.all(
    [pingAuth(), pingBilling(), pingSearch()] as const,
    { concurrency: "unbounded" }
  ).pipe(
    Effect.map(() => ({ auth: "ok", billing: "ok", search: "ok" }) as const),
    Effect.catchTags({
      AuthDown: () => Effect.fail(new ServiceDown({ which: "auth" })),
      BillingDown: () => Effect.fail(new ServiceDown({ which: "billing" })),
      SearchDown: () => Effect.fail(new ServiceDown({ which: "search" })),
    })
  );
```

Parallel `Effect.all` merges the three distinct failure tags; `Effect.catchTags` remaps them into a single typed `ServiceDown` while winning pings stay in the tuple success.

