import { Effect, Data } from "effect";

interface Account { readonly id: string; readonly balance: number }
interface FxRate { readonly pair: string; readonly rate: number }
interface Charge { readonly id: string }

class AccountError extends Data.TaggedError("AccountError")<{}> {}
class FxError extends Data.TaggedError("FxError")<{}> {}
class ChargeError extends Data.TaggedError("ChargeError")<{}> {}

declare const loadAccount: (id: string) => Effect.Effect<Account, AccountError>;
declare const loadRate: (pair: string) => Effect.Effect<FxRate, FxError>;
declare const chargeAt: (a: Account, r: FxRate) => Effect.Effect<Charge, ChargeError>;

export const pay = (
  id: string,
  pair: string
): Effect.Effect<Charge, AccountError | FxError | ChargeError> =>
  Effect.gen(function* () {
    // Run the two lookups concurrently.
    const [account, rate] = yield* Effect.all(
      [loadAccount(id), loadRate(pair)] as const,
      { concurrency: "unbounded" }
    );
    // Sequential dependency follows.
    return yield* chargeAt(account, rate);
  });
```

The parallel `Effect.all` shortens total latency for the two independent lookups; the charge step naturally sequences after because it depends on both results.

