import { Effect, Data } from "effect";

interface Rendered { readonly id: string; readonly html: string }

class IdsError extends Data.TaggedError("IdsError")<{}> {}
class RenderError extends Data.TaggedError("RenderError")<{ readonly id: string }> {}

declare const topIds: () => Effect.Effect<ReadonlyArray<string>, IdsError>;
declare const render: (id: string) => Effect.Effect<Rendered, RenderError>;

