```ts
import { Effect, Data, Console } from "effect";

class LogError extends Data.TaggedError("LogError")<{ readonly sink: string }> {}

declare const writeLine: (sink: string, line: string) => Effect.Effect<number, LogError>;

export const broadcast = (
  line: string,
  sinks: ReadonlyArray<string>
): Effect.Effect<void, LogError> =>
  Effect.all(
    sinks.map((s) => writeLine(s, line)),
    { concurrency: "unbounded", discard: true }
  ).pipe(Effect.tap(() => Console.log(`fanout done (${sinks.length})`)));
```

`discard: true` drops the per-fibre `number` results so the effect's success type collapses to `void`; the `LogError` channel is preserved untouched, and `Effect.tap` lets you observe completion without affecting the value.

Use sequential `Effect.all` (the default) when the remote has strict rate limits or when each call depends on observable side effects of the previous one (cursor pagination, lock acquisition, transactional writes). Parallel `Effect.all` with `concurrency: "unbounded"` or a numeric cap is right when the calls are truly independent and the remote can absorb the load.

```ts
import { Effect, Data } from "effect";

class RateLimited extends Data.TaggedError("RateLimited")<{}> {}

declare const call: (id: string) => Effect.Effect<string, RateLimited>;

// Sequential: safe under a strict 1-request-per-call rate limit.
export const callAllSerial = (
  ids: ReadonlyArray<string>
): Effect.Effect<ReadonlyArray<string>, RateLimited> =>
  Effect.all(ids.map(call));

// Parallel-bounded: safe for quotas that allow 3 in flight.
export const callAllPooled = (
  ids: ReadonlyArray<string>
): Effect.Effect<ReadonlyArray<string>, RateLimited> =>
  Effect.all(ids.map(call), { concurrency: 3 });

// Either mode, wrapped in a generator for easy extension.
export const callAllLogged = (
  ids: ReadonlyArray<string>
): Effect.Effect<ReadonlyArray<string>, RateLimited> =>
  Effect.gen(function* () {
    const results = yield* callAllPooled(ids);
    return results;
  });
```

Both keep the tuple/array order and the typed `RateLimited` error channel identical; only the scheduling changes.

