```

Default `Effect.all` semantics: the first failure interrupts every remaining fibre, and the failure is surfaced in the union `E` channel of the tuple result.

```ts
import { Effect, Data } from "effect";

class AuthSvcError extends Data.TaggedError("AuthSvcError")<{}> {}
class BillingSvcError extends Data.TaggedError("BillingSvcError")<{}> {}
class MailSvcError extends Data.TaggedError("MailSvcError")<{}> {}
class ConfirmError extends Data.TaggedError("ConfirmError")<{ readonly system: string }> {}

declare const deleteAuth: (id: string) => Effect.Effect<void, AuthSvcError>;
declare const deleteBilling: (id: string) => Effect.Effect<void, BillingSvcError>;
declare const deleteMail: (id: string) => Effect.Effect<void, MailSvcError>;

export const confirmDeletion = (
  id: string
): Effect.Effect<void, ConfirmError> =>
  Effect.all(
    [deleteAuth(id), deleteBilling(id), deleteMail(id)] as const,
    { concurrency: "unbounded", discard: true }
  ).pipe(
    Effect.catchTags({
      AuthSvcError: () => Effect.fail(new ConfirmError({ system: "auth" })),
      BillingSvcError: () => Effect.fail(new ConfirmError({ system: "billing" })),
      MailSvcError: () => Effect.fail(new ConfirmError({ system: "mail" })),
    })
  );
```

`discard: true` keeps the success type as `void`; `catchTags` funnels the three distinct branch errors into the single `ConfirmError` tag with the offending system recorded.

