  pipe(ids.map(fetchOne), Effect.allWith({ concurrency: 4 }));

// Sequential variant, for contrast — no options passed.
export const fetchAllSerial = (
  ids: ReadonlyArray<string>
): Effect.Effect<ReadonlyArray<string>, FetchError> =>
  Effect.all(ids.map(fetchOne));
```

`Effect.allWith({...})` is the pipeable form of `Effect.all(..., {...})`; both produce identical result types, and using the standalone `pipe(input, Effect.allWith({...}))` composes naturally with upstream array transforms.

