```ts
import { Effect, Data } from "effect";

class ProvisionError extends Data.TaggedError("ProvisionError")<{ readonly step: string }> {}

interface Tenant { readonly id: string }

declare const createTenant: (name: string) => Effect.Effect<Tenant, ProvisionError>;
declare const createBucket: (t: Tenant) => Effect.Effect<void, ProvisionError>;
declare const createQueue: (t: Tenant) => Effect.Effect<void, ProvisionError>;
declare const createIndex: (t: Tenant) => Effect.Effect<void, ProvisionError>;

export const provision = (name: string): Effect.Effect<Tenant, ProvisionError> =>
  Effect.gen(function* () {
    // Sequential: tenant must exist before resources reference it.
    const tenant = yield* createTenant(name);
    // Parallel: the three resources are independent of each other.
    yield* Effect.all(
      [createBucket(tenant), createQueue(tenant), createIndex(tenant)] as const,
      { concurrency: "unbounded", discard: true }
    );
    return tenant;
  });
```

Dependencies dictate scheduling: `createTenant` blocks the generator; the downstream resources share no data and thus go into `Effect.all` with `"unbounded"` concurrency.

