class AclError extends Data.TaggedError("AclError")<{}> {}

declare const authenticate: () => Effect.Effect<Token, AuthError>;
declare const fetchProfile: () => Effect.Effect<Profile, ProfileError>;
declare const fetchAcl: () => Effect.Effect<Permissions, AclError>;

export const bootstrap: Effect.Effect<string, AuthError | ProfileError | AclError> =
  Effect.gen(function* () {
    const [token, profile, acl] = yield* Effect.all(
      [authenticate(), fetchProfile(), fetchAcl()] as const,
      { concurrency: "unbounded" }
    );
    const canRead = acl.roles.includes("reader");
    return `${profile.id}:${canRead ? token.jwt : ""}`;
  });
```

The destructuring `const [token, profile, acl]` is fully typed off the tuple literal — each variable gets its corresponding element's type with no casts.
